const allInputs = $input.all();
const bill = (allInputs[0]?.json?.data || allInputs[0]?.json) || {};
const analysis = allInputs[1]?.json?.answer || allInputs[1]?.json?.markdown || '';
const fileName = $('New Medical Bill').item.json.name;
const fileId   = $('New Medical Bill').item.json.id;

const errors = (bill.potentialErrorsList || '').split(';').filter(Boolean);
const errorsList = errors.map(e => `⚠️ ${e.trim()}`).join('\n') || 'None found';
const flagCount = [bill.duplicateCharges, bill.upcoding, bill.unbundling, bill.medicallyUnnecessary].filter(Boolean).length;

return [{ json: {
  patientName:     bill.patientName     || 'N/A',
  accountNumber:   bill.accountNumber   || 'N/A',
  providerName:    bill.providerName    || 'N/A',
  serviceDate:     bill.serviceDate     || 'N/A',
  totalBilled:     bill.totalBilled     || 0,
  amountDue:       bill.amountDue       || 0,
  insurancePaid:   bill.insurancePaid   || 0,
  errorsList, errorsCount: errors.length, flagCount,
  potentialErrorsList: bill.potentialErrorsList || 'None',
  duplicateCharges: bill.duplicateCharges || false,
  analysis,
  fileName, fileId,
  processedAt: new Date().toISOString(),
  fileId: fileId,
  dateOfService: bill.serviceDate || "N/A",
  admissionDate: bill.serviceDate || "N/A",
  dischargeDate: bill.serviceDate || "N/A",
  paymentDueDate: bill.dueDate || "N/A",
  patientResponsibility: bill.patientResponsibility || 0,
  issueCount: errors.length,
  disputePriority: errors.length > 2 ? "High" : errors.length > 0 ? "Medium" : "Low",
  analysisReport: analysis,
}}];

